// Transform MLS Grid record into Supabase expired_listings row
const mls = $('Split Into Items').item.json;

const listingContractDate = mls.ListingContractDate ? new Date(mls.ListingContractDate) : null;
const expiredDate = mls.ModificationTimestamp ? new Date(mls.ModificationTimestamp) : new Date();
let daysOnMarket = null;
if (listingContractDate && expiredDate) {
  daysOnMarket = Math.floor((expiredDate - listingContractDate) / (1000 * 60 * 60 * 24));
}

return [{
  json: {
    listing_key: mls.ListingKey,
    listing_id: (mls.ListingId || '').replace('MFR', ''),
    street_number: mls.StreetNumber || null,
    street_name: mls.StreetName || null,
    street_suffix: mls.StreetSuffix || null,
    full_address: mls.UnparsedAddress || [mls.StreetNumber, mls.StreetName, mls.StreetSuffix].filter(Boolean).join(' '),
    city: mls.City || null,
    state: mls.StateOrProvince || null,
    zip: mls.PostalCode || null,
    county: mls.CountyOrParish || null,
    latitude: mls.Latitude || null,
    longitude: mls.Longitude || null,
    property_type: mls.PropertyType || null,
    property_subtype: mls.PropertySubType || null,
    bedrooms: mls.BedroomsTotal || null,
    bathrooms: mls.BathroomsTotalInteger || null,
    sqft: mls.LivingArea || null,
    year_built: mls.YearBuilt || null,
    list_price: mls.ListPrice || null,
    original_list_price: mls.OriginalListPrice || null,
    previous_list_price: mls.PreviousListPrice || null,
    listing_contract_date: mls.ListingContractDate || null,
    expired_date: mls.ModificationTimestamp || null,
    days_on_market: daysOnMarket,
    listing_agent_name: mls.ListAgentFullName || null,
    listing_agent_email: mls.ListAgentEmail || null,
    listing_agent_phone: mls.ListAgentDirectPhone || null,
    listing_office_name: mls.ListOfficeName || null,
    listing_office_phone: mls.ListOfficePhone || null,
    status: 'pending_skip_trace',
    raw_data: mls
  }
}];

// Build CSV content for Tracerfy from the listing data
const listing = $('Transform Listing Data').item.json;
const address = listing.full_address || [listing.street_number, listing.street_name, listing.street_suffix].filter(Boolean).join(' ');
const city = listing.city || '';
const state = listing.state || '';

const csvContent = `address,city,state\n${address},${city},${state}`;

return [{
  json: {
    csvContent,
    address,
    city,
    state,
    listing_id: $('Insert Listing').item.json.id
  }
}];

// Parse Tracerfy response into skip_trace_results format
const traceData = $json;
const listingId = $('Build CSV for Tracerfy').item.json.listing_id;

// Tracerfy returns results in its queue response — exact structure
// will need to be verified with a live API call. Below is the expected mapping.
const result = traceData.results ? traceData.results[0] : traceData;

const phoneNumbers = [];
// Tracerfy returns up to 8 phone numbers
for (let i = 1; i <= 8; i++) {
  const phone = result[`phone_${i}`] || result[`phone${i}`];
  const type = result[`phone_${i}_type`] || result[`phone${i}_type`] || 'unknown';
  if (phone) {
    phoneNumbers.push({ number: phone, type: type });
  }
}

const emailAddresses = [];
// Tracerfy returns up to 5 emails
for (let i = 1; i <= 5; i++) {
  const email = result[`email_${i}`] || result[`email${i}`];
  if (email) {
    emailAddresses.push(email);
  }
}

return [{
  json: {
    listing_id: listingId,
    owner_name: result.owner_name || result.first_name && result.last_name ? `${result.first_name} ${result.last_name}` : null,
    phone_numbers: phoneNumbers,
    email_addresses: emailAddresses,
    mailing_address: result.mailing_address || null,
    skip_trace_provider: 'tracerfy',
    skip_trace_cost: 0.02,
    success: phoneNumbers.length > 0 || emailAddresses.length > 0,
    raw_response: traceData
  }
}];

// Build GHL contact payload from listing + skip trace data
const listing = $('Transform Listing Data').item.json;
const trace = $('Parse Trace Results').item.json;

// Split owner name into first/last
const nameParts = (trace.owner_name || '').split(' ');
const firstName = nameParts[0] || 'Property';
const lastName = nameParts.slice(1).join(' ') || 'Owner';

// Primary phone and email
const primaryPhone = trace.phone_numbers.length > 0 ? trace.phone_numbers[0].number : null;
const primaryEmail = trace.email_addresses.length > 0 ? trace.email_addresses[0] : null;

const payload = {
  locationId: $vars.GHL_LOCATION_ID,
  firstName: firstName,
  lastName: lastName,
  phone: primaryPhone,
  email: primaryEmail,
  address1: listing.full_address,
  city: listing.city,
  state: listing.state,
  postalCode: listing.zip,
  source: 'Expired MLS Listing',
  tags: ['expired-listing', 'mls-lead', 'equitypro'],
  customFields: [
    // IMPORTANT: Replace these IDs with actual custom field IDs from GHL
    // Create these fields in GHL first, then update the IDs here
    { id: 'REPLACE_listing_price', field_value: String(listing.list_price || '') },
    { id: 'REPLACE_original_list_price', field_value: String(listing.original_list_price || '') },
    { id: 'REPLACE_bedrooms', field_value: String(listing.bedrooms || '') },
    { id: 'REPLACE_bathrooms', field_value: String(listing.bathrooms || '') },
    { id: 'REPLACE_sqft', field_value: String(listing.sqft || '') },
    { id: 'REPLACE_year_built', field_value: String(listing.year_built || '') },
    { id: 'REPLACE_mls_number', field_value: listing.listing_id || '' },
    { id: 'REPLACE_property_type', field_value: listing.property_type || '' },
    { id: 'REPLACE_county', field_value: listing.county || '' },
    { id: 'REPLACE_days_on_market', field_value: String(listing.days_on_market || '') },
    { id: 'REPLACE_listing_agent', field_value: listing.listing_agent_name || '' },
    { id: 'REPLACE_expired_date', field_value: listing.expired_date || '' }
  ]
};

return [{ json: payload }];

// Increment the billing counter
const currentUsed = $('Check Billing Cap').item.json.skip_traces_used || 0;
return [{ json: { skip_traces_used: currentUsed + 1 } }];
